function mdFilePathToUrl(mdFilePath: string, pageSourceDir: string, baseUrl: string) {
	const pathBelowRoot = path.relative(pageSourceDir, mdFilePath);
	const pathname = pathBelowRoot.replace(/\\/g, '/').replace(/\.mdx?$/i, '/');

	return new URL(pathname, baseUrl);
}

function getLanguageCodeFromPathname(pathname: string) {
	// Assuming that `pathname` always starts with a `/`, retrieve the first path part,
	// which is usually the language code
	const firstPathPart = pathname.split('/')[1];
	// Only return parts that look like a two-letter language code
	// with optional two-letter country code
	if (firstPathPart.match(/^[a-z]{2}(-[a-zA-Z]{2})?$/)) return firstPathPart;
}

export function getPagePathnamesFromSitemap(options: LinkCheckerOptions) {
	const distContents = fs.readdirSync(options.buildOutputDir);
	const sitemaps = distContents.filter((path) => /^sitemap-\d+\.xml$/.test(path));

	const sitemapRegex = new RegExp(`<loc>${options.baseUrl}(/.*?)</loc>`, 'ig');
	const uniquePagePaths = new Set<string>();

	for (const filename of sitemaps) {
		const sitemapFilePath = path.join(options.buildOutputDir, filename);
		const sitemap = fs.readFileSync(sitemapFilePath, 'utf8');
		const paths = Array.from(sitemap.matchAll(sitemapRegex), (m) => m[1]);
		paths.forEach((path) => uniquePagePaths.add(path));
	}

	return Array.from(uniquePagePaths);
}

export function getNewestCommitDate(file: string): Date {
	const result = spawnSync('git', ['log', '--format=%ct', '--max-count=1', basename(file)], {
		cwd: dirname(file),
		encoding: 'utf-8',
	});

	if (result.error) {
		throw new Error(`Failed to retrieve the git history for file "${file}"`);
	}
	const output = result.stdout.trim();
	const regex = /^(?<timestamp>\d+)$/;
	const match = output.match(regex);

	if (!match?.groups?.timestamp) {
		throw new Error(`Failed to validate the timestamp for file "${file}"`);
	}

	const timestamp = Number(match.groups.timestamp);
	const date = new Date(timestamp * 1000);
	return date;
}

export function applyThemeToDocument(theme: LIGHT_DARK_MODE) {
	switch (theme) {
		case LIGHT_MODE:
			document.documentElement.classList.remove("dark");
			break;
		case DARK_MODE:
			document.documentElement.classList.add("dark");
			break;
		case AUTO_MODE:
			if (window.matchMedia("(prefers-color-scheme: dark)").matches) {
				document.documentElement.classList.add("dark");
			} else {
				document.documentElement.classList.remove("dark");
			}
			break;
	}

	// Set the theme for Expressive Code
	document.documentElement.setAttribute(
		"data-theme",
		expressiveCodeConfig.theme,
	);
}

export function parseDirectiveNode() {
	return (tree, { _data }) => {
		visit(tree, (node) => {
			if (
				node.type === "containerDirective" ||
				node.type === "leafDirective" ||
				node.type === "textDirective"
			) {
				// biome-ignore lint/suspicious/noAssignInExpressions: <check later>
				const data = node.data || (node.data = {});
				node.attributes = node.attributes || {};
				if (
					node.children.length > 0 &&
					node.children[0].data &&
					node.children[0].data.directiveLabel
				) {
					// Add a flag to the node to indicate that it has a directive label
					node.attributes["has-directive-label"] = true;
				}
				const hast = h(node.name, node.attributes);

				data.hName = hast.tagName;
				data.hProperties = hast.properties;
			}
		});
	};
}

export function redirectTemplate({
	status,
	absoluteLocation,
	relativeLocation,
	from,
}: RedirectTemplate) {
	// A short delay causes Google to interpret the redirect as temporary.
	// https://developers.google.com/search/docs/crawling-indexing/301-redirects#metarefresh
	const delay = status === 302 ? 2 : 0;
	const rel = escape(String(relativeLocation));
	const abs = escape(String(absoluteLocation));
	const fromHtml = from ? `from <code>${escape(from)}</code> ` : '';
	return `<!doctype html>
<title>Redirecting to: ${rel}</title>
<meta http-equiv="refresh" content="${delay};url=${rel}">
<meta name="robots" content="noindex">
<link rel="canonical" href="${abs}">
<body>
	<a href="${rel}">Redirecting ${fromHtml}to <code>${rel}</code></a>
</body>`;
}

async function verifyDirectories(options = {}) {
  // Ensure options object is properly initialized with defaults
  const opts = {
    verbose: false,
    ...options
  }

  let allExist = true

  for (const config of WATCH_CONFIGS) {
    try {
      await fs.access(config.dir, fs.constants.F_OK)
      if (opts.verbose) {
        log(`Verified directory ${path.relative(projectRoot, config.dir)} exists`, 'info')
      }
    } catch {
      log(`Warning: Directory ${path.relative(projectRoot, config.dir)} does not exist`, 'warning')
      allExist = false
    }
  }

  return allExist
}

export function AdmonitionComponent(properties, children, type) {
	if (!Array.isArray(children) || children.length === 0)
		return h(
			"div",
			{ class: "hidden" },
			'Invalid admonition directive. (Admonition directives must be of block type ":::note{name="name"} <content> :::")',
		);

	let label = null;
	if (properties?.["has-directive-label"]) {
		label = children[0]; // The first child is the label
		// biome-ignore lint/style/noParameterAssign: <check later>
		children = children.slice(1);
		label.tagName = "div"; // Change the tag <p> to <div>
	}

	return h("blockquote", { class: `admonition bdm-${type}` }, [
		h("span", { class: "bdm-title" }, label ? label : type.toUpperCase()),
		...children,
	]);
}

export function buildEmDashCsp(registry?: RegistryConfigInput): string {
	const connectSrc = ["connect-src 'self'"];
	const registryAggregatorOrigin = getRegistryAggregatorOrigin(registry);
	if (registryAggregatorOrigin) connectSrc.push(registryAggregatorOrigin);

	return [
		"default-src 'self'",
		"script-src 'self' 'unsafe-inline'",
		"style-src 'self' 'unsafe-inline'",
		connectSrc.join(" "),
		"form-action 'self'",
		"frame-ancestors 'none'",
		"img-src 'self' https: data: blob:",
		"object-src 'none'",
		"base-uri 'self'",
	].join("; ");
}
